('low health', 'Could somebody drop a heal on me?', 0, 0, '', 'Est-ce que quelqu’un pourrait me soigner?', 'Kann mich jemand heilen?', '', '', '¿Alguien podría curarme?', '', ''),
('low health', 'Hey! Better heal me now than rez later', 0, 0, '', 'Salut! Mieux vaut me soigner maintenant que me ressusciter plus tard.', 'Hey! Heilt mich lieber jetzt als mich später zu wiederbeleben.', '', '', '¡Oye! Mejor curarme ahora que resucitarme después', '', ''),
('low health', 'I am sorry. Need another heal', 0, 0, '', 'Je suis désolé. J’ai besoin d’une autre guérison.', 'Tut mir leid. Brauche nochmal Heilung.', '', '', 'Lo siento. Necesito otra curación', '', ''),
('low health', 'Damn mobs. Heal me please', 0, 0, '', 'Maudits mobs. Guéris moi s’il te plait', 'Verdammte Mobs. Heilt mich bitte.', '', '', '¡Malditos bichos! ¡Una curita por favor!', '', ''),
('low health', 'One more hit and I am done for. Heal please', 0, 0, '', 'Un coup de plus et c’est fini. Guéris moi s’il te plait', 'Ein Treffer noch und ich bin erledigt. Heilung bitte.', '', '', 'Un golpe más y estoy acabado. Cura por favor', '', ''),
('low health', 'Are there any healers?', 0, 0, '', 'Y a-t-il des guérisseurs?', 'Gibt es hier Heiler?', '', '', '¿Hay sanadores?', '', ''),
('low health', 'Why do they always punch me in the face? Need heal', 0, 0, '', 'Pourquoi est-ce qu’ils me frappent toujours au visage? J’ai besoin de guérison', 'Warum schlagen sie mir immer ins Gesicht? Brauche Heilung.', '', '', '¿Por qué siempre me golpean en la cara? Necesito sanacion', '', ''),
