('broadcast_looting_item_poor', 'There’s %item_link, again. What a surprise.', 0, 0, '', 'Encore %item_link. Quelle surprise.', 'Schon wieder %item_link. Was für eine Überraschung.', '', '', '', '', ''),
('broadcast_looting_item_poor', 'I guess %item_link is good for vendor trash?', 0, 0, '', 'I présume qu’ %item_link est bon pour vendre à un marchand ?', 'Ich schätze, %item_link taugt immerhin als Müll für den Händler?', '', '', '', '', ''),
