('broadcast_quest_accepted_generic', 'I have just taken the %quest_link', 0, 0, '', 'Je viens de commencer %quest_link.', 'Ich habe gerade %quest_link angenommen.', '', '', '', '', ''),
('broadcast_quest_accepted_generic', 'just accepted %quest_link', 0, 0, '', 'Je viens d’accepter %quest_link', 'Hab gerade %quest_link angenommen.', '', '', '', '', ''),
