('broadcast_quest_turned_in', 'Yess, I have finally turned in the %quest_link', 0, 0, '', 'Oh ouiii, j’ai enfin remis la %quest_link', 'Ja, endlich %quest_link abgegeben!', '', '', '', '', ''),
('broadcast_quest_turned_in', 'turned in the %quest_link', 0, 0, '', 'J’ai soumis %quest_link.', '%quest_link abgegeben.', '', '', '', '', ''),
('broadcast_quest_turned_in', 'managed to finish %quest_link, just turned in', 0, 0, '', 'J’ai réussi à terminer %quest_link, je viens tout juste de le remettre.', '%quest_link abgeschlossen und gerade abgegeben.', '', '', '', '', ''),
('broadcast_quest_turned_in', 'just turned in %quest_link', 0, 0, '', 'Je viens de remettre %quest_link.', 'Gerade %quest_link abgegeben.', '', '', '', '', ''),
('broadcast_quest_turned_in', 'just turned in %quest_link in %zone_name', 0, 0, '', 'Je viens de terminer la quête %quest_link dans la zone %zone_name.', 'Gerade %quest_link in %zone_name abgeschlossen.', '', '', '', '', ''),
('broadcast_quest_turned_in', 'Another quest completed! %quest_link turned in', 0, 0, '', 'Encore une quête terminée! %quest_link remise', 'Noch eine Quest erledigt! %quest_link abgegeben.', '', '', '', '', ''),
('broadcast_quest_turned_in', 'Mission accomplished! %quest_link is turned in', 0, 0, '', 'Mission accomplie ! J’ai remis %quest_link.', 'Mission erfüllt! %quest_link abgegeben.', '', '', '', '', ''),
('broadcast_quest_turned_in', 'Finally, %quest_link turned in! That was a journey!', 0, 0, '', 'Enfin, j’ai remis la %quest_link ! Quelle aventure !', 'Endlich %quest_link abgegeben! Was für eine Reise!', '', '', '', '', ''),
('broadcast_quest_turned_in', 'Just completed %quest_link and turned it in, feeling good!', 0, 0, '', 'Je viens de terminer %quest_link et de le rendre, je me sens bien !', 'Gerade %quest_link abgeschlossen und abgegeben, fühlt sich gut an!', '', '', '', '', ''),
('broadcast_quest_turned_in', 'Turned in %quest_link in %zone_name. Now, on to the next challenge!', 0, 0, '', 'J’ai remis la %quest_link dans %zone_name. Maintenant, je passe au défi suivant !', '%quest_link in %zone_name abgegeben. Jetzt weiter zur nächsten Herausforderung!', '', '', '', '', ''),
('broadcast_quest_turned_in', 'I have turned in %quest_link. One more down!', 0, 0, '', 'J’ai remis %quest_link. Un de moins à faire !', '%quest_link abgegeben. Wieder eine weniger!', '', '', '', '', ''),
('broadcast_quest_turned_in', 'Successfully turned in %quest_link, that took a while!', 0, 0, '', 'J’ai enfin réussi à remettre la %quest_link, ça m’a pris du temps !', '%quest_link endlich abgegeben, das hat gedauert!', '', '', '', '', ''),
('broadcast_quest_turned_in', 'Completed and turned in %quest_link in %zone_name. Feels great!', 0, 0, '', 'J’ai terminé et remis la %quest_link dans la zone %zone_name. Je me sens génial!', '%quest_link in %zone_name abgeschlossen und abgegeben. Fühlt sich super an!', '', '', '', '', ''),
('broadcast_quest_turned_in', 'Quest complete! %quest_link turned in and ready for the next one!', 0, 0, '', 'Quête terminée! J’ai remis %quest_link et je suis prêt pour la prochaine!', 'Quest abgeschlossen! %quest_link abgegeben und bereit für die nächste!', '', '', '', '', ''),
('broadcast_quest_turned_in', 'Finally turned in %quest_link in %zone_name. That one was tough!', 0, 0, '', 'Je viens enfin de rendre la %quest_link dans la zone de %zone_name. Celle-là était vraiment coriace !', 'Endlich %quest_link in %zone_name abgegeben. Die war echt hart!', '', '', '', '', ''),
('broadcast_quest_turned_in', 'That’s it, %quest_link turned in! Now to collect the reward!', 0, 0, '', 'C’est bon, la %quest_link est terminée ! Maintenant, je vais chercher ma récompense !', 'Geschafft, %quest_link abgegeben! Jetzt die Belohnung abholen!', '', '', '', '', ''),
('broadcast_quest_turned_in', 'Finished %quest_link! Now time to turn it in and move on.', 0, 0, '', 'J’ai fini la %quest_link ! Maintenant, il est temps de la remettre et de passer à la suite.', '%quest_link abgeschlossen! Jetzt abgeben und weiter geht’s.', '', '', '', '', ''),
('broadcast_quest_turned_in', 'Just turned in %quest_link, feeling accomplished!', 0, 0, '', 'Je viens juste de terminer %quest_link, je me sens tellement accompli !', 'Gerade %quest_link abgegeben, fühlt sich gut an!', '', '', '', '', ''),
('broadcast_quest_turned_in', 'I’ve turned in %quest_link. Let’s see what’s next!', 0, 0, '', 'J’ai remis %quest_link. Voyons ce qui nous attend ensuite!', 'Hab %quest_link abgegeben. Mal sehen, was als Nächstes kommt!', '', '', '', '', ''),
('broadcast_quest_turned_in', 'Just wrapped up %quest_link and turned it in. On to the next one!', 0, 0, '', 'Je viens de terminer %quest_link et de la rendre. En route pour la suite !', '%quest_link abgeschlossen und abgegeben. Weiter geht’s!', '', '', '', '', ''),
('broadcast_quest_turned_in', 'Another one in the books, %quest_link turned in', 0, 0, '', 'Encore une de faite, %quest_link remise.', 'Wieder eine erledigt, %quest_link abgegeben.', '', '', '', '', ''),
('broadcast_quest_turned_in', 'Turned in %quest_link! Time to collect my rewards.', 0, 0, '', 'J’ai rendu la %quest_link! Il est temps de récupérer mes récompenses.', '%quest_link abgegeben! Zeit, die Belohnung einzusacken.', '', '', '', '', ''),
('broadcast_quest_turned_in', 'Completed and turned in %quest_link, what a relief!', 0, 0, '', 'J’ai terminé et remis %quest_link, quel soulagement !', '%quest_link abgeschlossen und abgegeben, was für eine Erleichterung!', '', '', '', '', ''),
('broadcast_quest_turned_in', 'That was quick! %quest_link turned in already!', 0, 0, '', 'Déjà?! %quest_link a été rendu si rapidement!', 'Das ging schnell! %quest_link schon abgegeben!', '', '', '', '', ''),
('broadcast_quest_turned_in', 'Just turned in %quest_link in %zone_name. Ready for the next adventure!', 0, 0, '', 'Je viens de rendre %quest_link dans %zone_name. Je suis prêt pour la prochaine aventure !', 'Gerade %quest_link in %zone_name abgegeben. Bereit für das nächste Abenteuer!', '', '', '', '', ''),
('broadcast_quest_turned_in', 'Successfully turned in %quest_link. Feels like progress!', 0, 0, '', 'J’ai réussi à rendre %quest_link. On dirait que j’avance!', '%quest_link erfolgreich abgegeben. Fühlt sich nach Fortschritt an!', '', '', '', '', ''),
