INSERT INTO `ai_playerbot_texts` (`name`, `text`, `say_type`, `reply_type`, `text_loc1`, `text_loc2`, `text_loc3`, `text_loc4`, `text_loc5`, `text_loc6`, `text_loc7`, `text_loc8`) VALUES
('broadcast_guild_promotion', 'Good job %other_name. You deserved this.', 0, 0, '', '', '', '', '', '', '', ''),
('broadcast_guild_promotion', 'Good job %other_name. You deserved this.', 0, 0, '', 'Bien joué %other_name. Tu l’as bien mérité.', 'Gut gemacht %other_name. Das hast du dir verdient.', '', '', '', '', ''),
('broadcast_guild_demotion', 'That was awful %other_name. I hate to do this but...', 0, 0, '', 'Désolé %other_name, mais ça a été horrible. Je déteste devoir faire ça, mais...', 'Das war echt schlecht %other_name. Ich hasse es, das zu tun, aber...', '', '', '', '', ''),
('broadcast_guild_promotion', 'Congrats %other_name, you’ve earned this promotion!', 0, 0, '', 'Félicitations %other_name, tu as mérité cette promotion !', 'Glückwunsch %other_name, du hast dir diese Beförderung verdient!', '', '', '', '', ''),
('broadcast_guild_promotion', 'Well deserved %other_name, welcome to the next level!', 0, 0, '', 'Bien mérité %other_name, bienvenue au niveau suivant !', 'Verdient %other_name, willkommen auf der nächsten Stufe!', '', '', '', '', ''),
('broadcast_guild_promotion', '%other_name is leveling up! Congratulations on the promotion!', 0, 0, '', '%other_name progresse dans sa carrière ! Félicitations pour la promotion !', '%other_name steigt auf! Glückwunsch zur Beförderung!', '', '', '', '', ''),
('broadcast_guild_promotion', 'Promotion time! %other_name, you’ve earned this one!', 0, 0, '', 'Promotion time! %other_name, tu l’as bien mérité !', 'Beförderungszeit! %other_name, das hast du dir verdient!', '', '', '', '', ''),
('broadcast_guild_promotion', 'A new role for %other_name! Well done, keep it up!', 0, 0, '', 'Une nouvelle fonction pour %other_name ! Bravo, continue comme ça !', 'Eine neue Rolle für %other_name! Gut gemacht, weiter so!', '', '', '', '', ''),
('broadcast_guild_promotion', 'Huge congrats to %other_name, you’ve earned a well-deserved promotion!', 0, 0, '', '%other_name, félicitations pour ta super promotion, tu la mérites amplement!', 'Große Glückwünsche an %other_name, du hast dir diese Beförderung verdient!', '', '', '', '', ''),
('broadcast_guild_promotion', 'Let’s all give a round of applause to %other_name, for the promotion!', 0, 0, '', 'Donnons tous un grand round d’applaudissements à %other_name pour sa promotion!', 'Lasst uns %other_name für die Beförderung applaudieren!', '', '', '', '', ''),
('broadcast_guild_promotion', 'Cheers to %other_name on the promotion! Keep shining!', 0, 0, '', 'Salut à %other_name pour sa promotion! Continue de briller!', 'Prost auf %other_name zur Beförderung! Bleib am Ball!', '', '', '', '', ''),
('broadcast_guild_promotion', 'Congrats %other_name, you’re moving up! Well done!', 0, 0, '', 'Félicitations %other_name, tu progresses dans ton parcours ! Bravo !', 'Glückwunsch %other_name, du steigst auf! Gut gemacht!', '', '', '', '', ''),
('broadcast_guild_promotion', 'Another step up for %other_name! Congratulations!', 0, 0, '', 'Encore une promotion pour %other_name ! Félicitations !', 'Noch ein Aufstieg für %other_name! Glückwunsch!', '', '', '', '', ''),
('broadcast_guild_demotion', 'Tough decision, but %other_name, you’ve been demoted. Time to step up!', 0, 0, '', 'Décision difficile, mais %other_name, tu as été rétrogradé. C’est le moment de te ressaisir!', 'Schwere Entscheidung, aber %other_name, du wurdest degradiert. Zeit, dich zu beweisen!', '', '', '', '', ''),
('broadcast_guild_demotion', 'Sorry %other_name, but it’s time for a demotion. Hope you come back stronger!', 0, 0, '', 'Désolé %other_name, mais c’est l’heure d’une rétrogradation. J’espère que tu reviendras plus fort !', 'Tut mir leid %other_name, aber es ist Zeit für eine Degradierung. Hoffe, du kommst stärker zurück!', '', '', '', '', ''),
('broadcast_guild_demotion', 'Unfortunately, %other_name, it’s a demotion this time. You’ll get ''em next time!', 0, 0, '', '', 'Leider, %other_name, handelt es sich diesmal um eine Degradierung. Das nächste Mal kriegst du sie!', '', '', '', '', ''),
('broadcast_guild_demotion', 'A hard decision, but %other_name, you’ve been demoted. Time to grind back up!', 0, 0, '', 'Une décision difficile, mais %other_name, tu as été rétrogradé. Il est temps de remonter la pente !', 'Schwere Entscheidung, aber %other_name, du wurdest degradiert. Zeit, dich wieder hochzuarbeiten!', '', '', '', '', ''),
('broadcast_guild_demotion', 'We hate to see it, but %other_name, it’s a demotion for now.', 0, 0, '', 'C’est toujours difficile à accepter, %other_name, mais pour le moment, c’est une rétrogradation.', 'Es ist nie schön, aber %other_name, du wurdest degradiert – vorerst.', '', '', '', '', ''),
('broadcast_guild_demotion', 'Sorry %other_name, your rank has been lowered. Let’s work harder together!', 0, 0, '', 'Désolé %other_name, ton rang a été abaissé. On va devoir redoubler d’efforts ensemble !', 'Tut mir leid %other_name, dein Rang wurde gesenkt. Lass uns gemeinsam härter arbeiten!', '', '', '', '', ''),
('broadcast_guild_demotion', 'A demotion for %other_name... Time to focus and rise back up!', 0, 0, '', 'Une rétrogradation pour %other_name... Il est temps de se concentrer et de remonter la pente!', 'Eine Degradierung für %other_name... Zeit, sich zu fokussieren und wieder aufzusteigen!', '', '', '', '', ''),
('broadcast_guild_demotion', 'Not what we wanted, but %other_name, you’ve been demoted. Learn and come back stronger!', 0, 0, '', 'Pas ce que nous voulions, mais %other_name, tu as été rétrogradé. Apprends et reviens plus fort !', 'Nicht das, was wir wollten, aber %other_name, du wurdest degradiert. Lern daraus und komm stärker zurück!', '', '', '', '', ''),
('broadcast_guild_demotion', 'A tough moment for %other_name, but we know you can bounce back from this demotion!', 0, 0, '', 'Un moment difficile pour %other_name, mais on sait que tu peux rebondir après cette rétrogradation!', 'Ein harter Moment für %other_name, aber wir wissen, dass du dich von dieser Degradierung erholen kannst!', '', '', '', '', ''),
('broadcast_guild_demotion', 'Sorry %other_name, but a demotion has been applied. It’s time for improvement!', 0, 0, '', 'Désolé %other_name, mais une rétrogradation a été appliquée. Il est temps de s’améliorer !', 'Tut mir leid %other_name, aber du wurdest degradiert. Jetzt ist es Zeit, sich zu verbessern!', '', '', '', '', ''),
('broadcast_guild_demotion', 'We didn’t want this for %other_name, but a demotion has occurred. Time to get better!', 0, 0, '', 'On n’a pas voulu cela pour %other_name, mais une rétrogradation a eu lieu. Il est temps de s’améliorer !', 'Das wollten wir nicht für %other_name, aber es ist zu einer Degradierung gekommen. Zeit, besser zu werden!', '', '', '', '', ''),
('broadcast_guild_recruitment', 'Looking for fresh blood! Join the guild, be part of something great!', 0, 0, '', 'À la recherche de sang neuf ! Rejoins la guilde, fais partie de quelque chose de grandiose !', 'Auf der Suche nach frischem Blut! Tritt der Gilde bei und sei Teil von etwas Großem!', '', '', '', '', ''),
('broadcast_guild_recruitment', 'Recruiting members! If you’re ready to join us, the guild door is open!', 0, 0, '', 'Recrutement de membres ! Si tu es prêt à nous rejoindre, la porte de la guilde est ouverte!', 'Wir rekrutieren! Wenn du bereit bist, uns beizutreten, steht die Tür der Gilde offen!', '', '', '', '', ''),
('broadcast_guild_recruitment', 'The guild is looking for skilled adventurers. Join us and thrive!', 0, 0, '', 'La guilde recherche des aventuriers compétents. Rejoins-nous et prospère!', 'Die Gilde sucht erfahrene Abenteurer. Tritt bei und wachse mit uns!', '', '', '', '', ''),
('broadcast_guild_recruitment', 'Want to join a great guild? We’re looking for new members! Come on in!', 0, 0, '', 'Envie de rejoindre une super guilde ? Nous cherchons de nouveaux membres ! Viens nous rejoindre !', 'Willst du einer großartigen Gilde beitreten? Wir suchen neue Mitglieder! Komm rein!', '', '', '', '', ''),
('broadcast_guild_recruitment', 'The guild is growing! Join us for exciting adventures and rewards!', 0, 0, '', 'La guilde grandit! Rejoignez-nous pour vivre des aventures palpitantes et obtenir des récompenses!', 'Die Gilde wächst! Schließ dich uns an für spannende Abenteuer und Belohnungen!', '', '', '', '', ''),
