('suggest_trade', 'Everyone is talking about %category.', 0, 0, '', 'Tout le monde parle de %category', '', '', '', 'Todos hablan de %category', '', ''),
('suggest_trade', 'I saw at least ten people farming for %category.', 0, 0, '', 'Jai vu au moins dix personnes farmer pour %category', '', '', '', 'Vi al menos diez personas farmeando para %category.', '', ''),
('suggest_trade', 'I sold all my %category yesterday. I am completely broke!', 0, 0, '', 'Jai vendu tout mon %category hier. Je suis complètement fauché!', '', '', '', 'Ayer vendí todo mi %category. ¡Estoy completamente arruinado!', '', ''),
('suggest_trade', 'Wanna join a guild farming for %category.', 0, 0, '', 'Je veux rejoindre une guilde farmant pour %category', '', '', '', 'Quiero unirme a una hermandad de farmeo para %category.', '', '');
INSERT INTO `ai_playerbot_texts` (`name`, `text`, `say_type`, `reply_type`, `text_loc1`, `text_loc2`, `text_loc3`, `text_loc4`, `text_loc5`, `text_loc6`, `text_loc7`, `text_loc8`) VALUES
('suggest_faction', 'Anyone farming %faction rep?', 0, 0, '', 'Qui ici farm la réputation de la faction %faction ?', 'Farmt jemand Ruf für %faction?', '', '', '¿Alguien farmea reputación con %faction?', '', ''),
('suggest_faction', 'Anyone help with %faction?', 0, 0, '', 'Besoin d’aide avec la réputation %faction?', 'Kann jemand bei %faction helfen?', '', '', '¿Alguien me ayuda con %faction?', '', ''),
('suggest_faction', 'Wanna quest for %faction.', 0, 0, '', 'Tu veux partir en quête pour la faction %faction?', 'Lust, Quests für %faction zu machen?', '', '', 'Quiero buscar a %faction.', '', ''),
('suggest_faction', '%faction is the best.', 0, 0, '', '%faction est la meilleure.', '%faction ist die beste.', '', '', '%faction es el mejor.', '', ''),
('suggest_faction', 'Need just a bit to be %rep_level with %faction.', 0, 0, '', 'J’ai juste besoin d’un peu pour être %rep_level avec %faction.', 'Brauche nur noch ein wenig für %rep_level bei %faction.', '', '', 'Solo necesito un poco para estar %rep_level con %faction.', '', ''),
('suggest_faction', 'Anyone got %rep_level with %faction?', 0, 0, '', 'Est-ce que quelqu’un a le niveau de réputation %rep_level avec %faction ?', 'Hat jemand schon %rep_level bei %faction?', '', '', '¿Alguien tiene %rep_level con %faction?', '', ''),
('suggest_faction', 'Who wants to be %rep_level with %faction?', 0, 0, '', 'Qui veut être %rep_level avec %faction?', 'Wer will %rep_level bei %faction erreichen?', '', '', '¿Quién quiere estar en %rep_level con %faction?', '', ''),
('suggest_faction', 'I’ll never be %rep_level with %faction.', 0, 0, '', 'Je ne serai jamais %rep_level souhaité avec %faction.', 'Ich werde niemals %rep_level bei %faction erreichen.', '', '', 'Nunca estaré %rep_level con %faction.', '', ''),
('suggest_faction', 'Someone missing %faction rep?', 0, 0, '', 'Quelqu’un manque de réputation auprès de %faction ?', 'Fehlt jemandem noch Ruf bei %faction?', '', '', '¿Alguien falta reputación con %faction?', '', ''),
('suggest_faction', 'Could help farming %faction rep.', 0, 0, '', 'Je peux t’aider à augmenter ta réputation avec %faction.', 'Ich kann beim Farmen von %faction-Ruf helfen.', '', '', 'Podría ayudar a farmear %faction rep.', '', ''),
('suggest_faction', 'The more rep the better. Especially with %faction.', 0, 0, '', 'Plus il y a de réput, mieux c’est. Surtout avec %faction', 'Je mehr Ruf, desto besser. Besonders bei %faction.', '', '', 'Cuantas más repeticiones, mejor. Especialmente con %faction.', '', ''),
('suggest_faction', '%faction: need %rndK for %rep_level.', 0, 0, '', '%faction: J’ai besoin de %rndK pour %rep_level.', '%faction: Brauche %rndK für %rep_level.', '', '', '%faction: necesita %rndK para %rep_level.', '', ''),
('suggest_faction', 'Who can share %faction quests?', 0, 0, '', 'Qui peut partager les quêtes de %faction?', 'Wer kann %faction-Quests teilen?', '', '', '¿Quién puede compartir misiones de %faction?', '', ''),
('suggest_faction', 'Any dungeons for %faction?', 0, 0, '', 'Des donjons pour %faction ?', 'Gibt es Dungeons für %faction?', '', '', '¿Alguna mazmorra para %faction?', '', ''),
('suggest_faction', 'Wanna do %faction rep grind.', 0, 0, '', 'Je veux monter ma réputation avec la %faction.', 'Ich will Ruf farmen für %faction.', '', '', 'Quiero hacer %faction rep grind.', '', ''),
('suggest_faction', 'Let’s farm %faction rep!', 0, 0, '', 'On va monter la réputation de la %faction !', 'Lass uns %faction-Ruf farmen!', '', '', '¡Vamos a farmear reputación con %faction!', '', ''),
('suggest_faction', 'Farming for %faction rep.', 0, 0, '', 'Je fais du farm pour gagner de la réputation auprès de %faction.', 'Ich farme Ruf für %faction.', '', '', 'Farming for %faction rep.', '', ''),
('suggest_faction', 'Wanna farm for %faction.', 0, 0, '', 'Envie de farmer pour %faction ?', 'Lust, %faction zu farmen?', '', '', 'Quiero farmear para %faction.', '', ''),
('suggest_faction', 'Need help with %faction.', 0, 0, '', 'Besoin d’aide avec %faction.', 'Brauche Hilfe mit %faction.', '', '', 'Necesito ayuda con %faction.', '', ''),
('suggest_faction', 'Is %faction sells something useful?', 0, 0, '', 'Est-ce que %faction vend quelque chose d’utile ?', 'Verkauft %faction etwas Nützliches?', '', '', '¿%faction vende algo útil?', '', ''),
('suggest_faction', 'Are there %faction vendors?', 0, 0, '', 'Y a-t-il des vendeurs de %faction ?', 'Gibt es Händler für %faction?', '', '', '¿Hay %proveedores de facciones?', '', ''),
('suggest_faction', 'Who farms %faction?', 0, 0, '', 'Ah, qui farm %faction?', 'Wer farmt %faction?', '', '', '¿Quién farmea %faction?', '', ''),
('suggest_faction', 'Which is the best way to farm %faction?', 0, 0, '', 'Quelle est la meilleurs façon de farmer %faction ?', 'Was ist die beste Methode, um %faction zu farmen?', '', '', '¿Cuál es la mejor manera de farmear %faction?', '', ''),
('suggest_faction', 'I hate %faction rep grind.', 0, 0, '', 'Je déteste ce fichu grind de réputation pour %faction.', 'Ich hasse das Ruf-Farmen für %faction.', '', '', 'Odio %repetir de facción', '', ''),
('suggest_faction', 'I am so tired of %faction.', 0, 0, '', 'Je suis tellement fatigué de cette %faction.', 'Ich bin so müde von %faction.', '', '', 'Estoy tan cansado de %faction.', '', ''),
('suggest_faction', 'Go for %faction?', 0, 0, '', 'Allez pour la %faction!', 'Gehen wir für %faction?', '', '', '¿Quereis ir a por %faction?', '', ''),
('suggest_faction', 'Seems everyone is %rep_level with %faction. Only me is late as usually.', 0, 0, '', 'Il semble que tout le monde soit au niveau %rep_level avec la faction %faction. Et bien sûr, je suis en retard comme d’habitude.', 'Sieht so aus, als wären alle %rep_level bei %faction. Nur ich bin wie immer zu spät.', '', '', 'Parece que todo el mundo está %rep_level con %faction. Solo yo llego tarde como siempre.', '', ''),
('suggest_faction', 'LFG for %faction rep grind?', 0, 0, '', 'Je recherche un groupe pour %faction rep grind !', 'Suche Gruppe für %faction Ruf-Farm!', '', '', 'Busco grupo para subir reputación con %faction', '', ''),
('suggest_faction', 'Can anobody suggest a good spot for %faction rep grind?', 0, 0, '', 'Est-ce que quelqu’un peut me recommander un bon endroit pour gagner de la réputation avec %faction?', 'Kann jemand einen guten Spot für %faction Ruf-Farm empfehlen?', '', '', '¿Alguien puede sugerir un buen lugar farmear reputacion con %faction?', '', ''),
('suggest_faction', 'Would %faction rep benefit me?', 0, 0, '', 'Est-ce que la réputation de %faction me sera bénéfique ?', 'Bringt mir der Ruf bei %faction etwas?', '', '', '¿Me beneficiaría subir reputación con %faction?', '', ''),
('suggest_faction', 'Who would’ve thought that %faction rep will be useful after all...', 0, 0, '', 'Qui aurait pensé que cette réputation %faction serait finalement utile...', 'Wer hätte gedacht, dass Ruf bei %faction doch nützlich ist...', '', '', 'Quién hubiera pensado que subir reputacion con %faction sería útil después de todo...', '', ''),
('suggest_faction', 'I wanna be exalted with all factions, starting with %faction.', 0, 0, '', 'Je veux être honoré par toutes les factions, commençant par %faction.', 'Ich will bei allen Fraktionen ehrfürchtig sein, angefangen mit %faction.', '', '', 'Quiero ser exaltado con todas las facciones, comenzando con %faction.', '', ''),
('suggest_faction', 'Is there any point to improve my rep with %faction?', 0, 0, '', 'Est-ce que ça vaut la peine d’améliorer ma réputation avec la faction %faction ?', 'Lohnt es sich, meinen Ruf bei %faction zu verbessern?', '', '', '¿Hay algún punto para mejorar mi reputación con %faction?', '', ''),
('suggest_faction', 'What is better for %faction? Quests or mob grinding?', 0, 0, '', 'Pour %faction, il vaut mieux grind des mobs ou faire des quêtes ?', 'Was ist besser für %faction? Quests oder Mob-Farming?', '', '', '¿Qué es mejor para %faction? ¿Misiones o mafiosos?', '', ''),
('suggest_faction', 'Will grind %faction rep for you. Just give me some gold.', 0, 0, '', 'Je vais augmenter la réputation de %faction pour toi. Il me suffit de me donner un peu d’or.', 'Ich farme %faction-Ruf für dich. Gib mir einfach etwas Gold.', '', '', 'Ganare reputacion con %faction por ti. Sólo dame un poco de oro.', '', ''),
('suggest_faction', 'I think grinding rep with %faction would take forever.', 0, 0, '', 'Je pense que monter ma réputation avec %faction prendrait une éternité.', 'Ich glaube, Ruf farmen für %faction dauert ewig.', '', '', 'Creo que subir la reputación con %faction tomaría una eternidad.', '', ''),
('suggest_faction', 'I am killing for %faction every day now but still far from %rep_level.', 0, 0, '', 'Je fais des missions pour la %faction tous les jours, mais je suis encore loin du niveau de réputation %rep_level.', 'Ich töte für %faction jeden Tag, aber bin noch weit entfernt von %rep_level.', '', '', 'Estoy matando por %faction todos los días ahora, pero aún estoy lejos del %rep_level.', '', ''),
('suggest_faction', 'At %my_level AH deposits will decrease, right?', 0, 0, '', 'À mon niveau %my_level, les dépôts AH vont diminuer, n’est-ce pas ?', 'Auf %my_level werden die Auktionshausgebühren sinken, oder?', '', '', 'Al %rep_level, los depósitos subastas disminuirán, ¿verdad?', '', ''),
('suggest_faction', 'How many exalted reps do you have?', 0, 0, '', 'Combien de représentants exaltés avez-vous?', 'Wie viele ehrfürchtige Rufe hast du?', '', '', '¿Cuántas reputaciones exaltadas tienes?', '', ''),
('suggest_faction', 'Who wants to be %my_level with %faction?', 0, 0, '', 'Qui veut être %my_level avec %faction?', 'Wer will %my_level bei %faction erreichen?', '', '', '¿Quién quiere estar en %rep_level con %faction?', '', ''),
('suggest_faction', 'Damn. My guild did a good %faction grind yesterday without me.', 0, 0, '', 'Mince. Mon groupe a bien grindé la réputation %faction hier sans moi.', 'Verdammt. Meine Gilde hat gestern ordentlich %faction gefarmt ohne mich.', '', '', 'Maldición. Mi hermandad hizo un buen farmeo de %faction ayer sin mí.', '', ''),
('suggest_faction', 'Nobody wants to help me because I am %rep_level with %faction.', 0, 0, '', 'Personne ne veut m’aider parce que je suis %rep_level avec %faction.', 'Niemand will mir helfen, weil ich %rep_level bei %faction bin.', '', '', 'Nadie quiere ayudarme porque estoy %rep_level con %faction.', '', ''),
('suggest_faction', 'Please stay away from %faction.', 0, 0, '', 'S’il te plaît, garde tes distances avec %faction.', 'Bitte halte dich von %faction fern.', '', '', 'Por favor manténgase alejado de %faction.', '', ''),
('suggest_faction', 'Anyone farming %faction rep today?', 0, 0, '', 'Vous êtes en train de farmer la réputation de %faction aujourd’hui ?', 'Farmt heute jemand %faction-Ruf?', '', '', '¿Alguien farmea reputación de %faction hoy?', '', ''),
('suggest_faction', 'Help me grind %faction rep!', 0, 0, '', 'Aide-moi à augmenter ma réputation avec la faction %faction!', 'Hilf mir, %faction-Ruf zu farmen!', '', '', '¡Ayúdame a subir mi reputación con %faction!', '', ''),
('suggest_faction', 'I need %rep_level with %faction so badly!', 0, 0, '', 'J’ai tellement besoin d’atteindre le niveau %rep_level avec la faction %faction !', 'Ich brauche unbedingt %rep_level bei %faction!', '', '', '¡Necesito %rep_level con %faction con urgencia!', '', ''),
('suggest_faction', 'Is %faction grind worth it?', 0, 0, '', 'Est-ce que le farm de %faction vaut vraiment la peine?', 'Lohnt sich das Farmen für %faction?', '', '', '¿Vale la pena el farmeo de %faction?', '', ''),
('suggest_faction', 'Anyone know %faction rep farm spots?', 0, 0, '', 'Je connais des endroits pour %faction pour augmenter ma réputation.', 'Kennt jemand gute Spots zum %faction-Ruf farmen?', '', '', '¿Alguien conoce lugares para farmear reputación con %faction?', '', ''),
('suggest_faction', 'I love grinding %faction rep!', 0, 0, '', 'J’adore augmenter ma réputation auprès de la faction %!', 'Ich liebe es, %faction-Ruf zu farmen!', '', '', '¡Me encanta hacer grind de reputación con %faction!', '', ''),
('suggest_faction', 'Need help to finish %faction rep grind!', 0, 0, '', 'Besoin d’aide pour finir ma montée de réputation avec %faction!', 'Brauche Hilfe, um meinen %faction-Ruf-Farm abzuschließen!', '', '', '¡Necesito ayuda para terminar el grind de reputación de %faction!', '', ''),
('suggest_faction', 'Only a few more %rep_level with %faction to go!', 0, 0, '', 'Il ne me reste que quelques niveaux de réputation à faire avec %faction !', 'Nur noch ein paar %rep_level bei %faction zu erreichen!', '', '', '¡Solo me faltan unos %rep_level para llegar a %faction!', '', ''),
('suggest_faction', 'Anyone up for %faction grind today?', 0, 0, '', 'Quelqu’un est motivé pour farmer la réputation de la %faction aujourd’hui?', 'Hat heute jemand Lust auf %faction-Ruf farmen?', '', '', '¿Alguien se anima al farmeo de %faction hoy?', '', ''),
('suggest_faction', 'Looking for %faction rep grind buddies!', 0, 0, '', 'À la recherche de compagnons de réputation de %faction! Qui est partant pour monter les réputations ensemble?', 'Suche Mitstreiter für %faction-Ruf farmen!', '', '', 'Busco compañeros para farmear %faction.', '', ''),
('suggest_faction', 'I’m tired of grinding %faction rep!', 0, 0, '', 'J’en ai marre de faire monter ma réputation auprès de la faction %faction !', 'Ich habe genug vom %faction-Ruf farmen!', '', '', '¡Estoy cansado de hacer grind de %faction!', '', ''),
('suggest_faction', 'Anyone on %faction rep grind too?', 0, 0, '', 'Oh, quelqu’un d’autre qui est en train de monter sa réputation avec %faction ?', 'Ist noch jemand dabei, %faction-Ruf zu farmen?', '', '', '¿Alguien más está haciendo el grind de %faction?', '', ''),
('suggest_faction', 'Time to hit %faction rep grind hard!', 0, 0, '', 'C’est le moment de faire le grind %faction sérieusement !', 'Zeit, den %faction-Ruf richtig zu farmen!', '', '', '¡Es hora de darle duro al grind de %faction!', '', ''),
('suggest_faction', 'Help me finish %faction rep!', 0, 0, '', 'Aide-moi à terminer ma réputation de faction !', 'Hilf mir, den %faction-Ruf abzuschließen!', '', '', '¡Ayúdame a completar la reputación de %faction!', '', ''),
('suggest_faction', 'Need just %rndK more for %faction rep!', 0, 0, '', 'Il ne me manque plus que %rndK pour augmenter ma réputation auprès de la faction!', 'Brauche nur noch %rndK für den %faction-Ruf!', '', '', '¡Solo me faltan %rndK para la reputación de %faction!', '', ''),
('suggest_faction', 'Grinding %faction rep all day!', 0, 0, '', 'À farmer la réputation de la faction toute la journée !', 'Den ganzen Tag %faction-Ruf farmen!', '', '', '¡Farmearé la reputación de %faction todo el día!', '', ''),
('suggest_faction', 'Almost at %rep_level with %faction!', 0, 0, '', 'Je suis presque au niveau %rep_level avec la faction %faction !', 'Fast %rep_level bei %faction erreicht!', '', '', '¡Casi al %rep_level con %faction!', '', ''),
('suggest_faction', '%faction rep grind never ends!', 0, 0, '', 'La réputation de faction, c’est jamais fini !', 'Das %faction-Ruf farmen nimmt kein Ende!', '', '', '¡El grind de reputación de %faction nunca termina!', '', ''),
('suggest_faction', 'Help with %faction daily quests?', 0, 0, '', 'Besoin d’aide avec les quêtes journalières de %faction ?', 'Brauche Hilfe mit den täglichen Quests für %faction!', '', '', '¿Ayuda con las misiones diarias de %faction?', '', ''),
('suggest_faction', 'Who’s on %faction grind right now?', 0, 0, '', 'Qui est en train de faire du %faction en ce moment ?', 'Wer farmt gerade %faction-Ruf?', '', '', '¿Quién está farmeando %faction ahora?', '', ''),
('suggest_faction', 'Let’s do %faction quests together!', 0, 0, '', 'Faisons des quêtes de faction ensemble!', 'Lasst uns zusammen %faction-Quests machen!', '', '', '¡Hagamos las misiones de %faction juntos!', '', ''),
('suggest_faction', 'Anyone farming %faction rep today?', 0, 0, '', 'Quelqu’un farme la réputation de la faction %faction aujourd’hui?', 'Farmt heute jemand %faction-Ruf?', '', '', '¿Alguien está farmeando reputación con %faction hoy?', '', ''),
('suggest_faction', 'Need %faction rep help for %rep_level!', 0, 0, '', 'Besoin d’aide pour la réputation de %faction %rep_level %rep_level !', 'Brauche Hilfe für %faction-Ruf bis %rep_level!', '', '', '¡Necesito ayuda con la reputación de %faction para %rep_level!', '', ''),
