('suggest_something_toxic', '%zone_name is for noobs. real players are in %area_name.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'can\'t believe I\'m grouped with a %my_class. yikes.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'imagine needing help in %zone_name. skill issue.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'hey, %random_inventory_item_link fits great in your mom\'s inventory.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'is ERP considered endgame content?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'looking for a guild, must have ERP as a core activity.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'bro, stop sucking at %zone_name and come help me.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'bet you can\'t even find %random_inventory_item_link without a map.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'who needs loot when you\'ve got daddy issues?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'ERP in %zone_name anyone? bring your main.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'didn\'t know %my_class could sink this low.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'bruh, %my_race players are so bad they make gnomes look good.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'you must be from %zone_name, cuz you\'re trash.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'oh cool, %random_inventory_item_link. must\'ve taken you years to loot.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'lol, %my_role players always die first. good job.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', '%my_class players thinking they\'re good is my favorite comedy.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'you\'re still in %zone_name? bro, this isn\'t 2004.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', '%zone_name is the perfect place for people who like being mediocre.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'oh look, %random_inventory_item_link. bet that\'ll carry you to victory... not.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'why are %my_race players always so salty? relax, dude.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'wow, another %my_role in %zone_name. how original.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', '%zone_name is basically daycare for bad players.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'great job, %my_role. you\'re about as useful as a gray item.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'bet you macro\'d %random_inventory_item_link just to feel useful.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'is %zone_name just where bad players go to die?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', '%random_inventory_item_link? bro, even vendors don\'t want that.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'wow, %my_role in %zone_name? groundbreaking.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', '%my_class players always thinking they\'re better than they are. lol.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'you must\'ve bought %random_inventory_item_link off eBay.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'how are %my_race still allowed in the game?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'bro, do you even know how to spec as %my_class?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'if %my_role was useful, you wouldn\'t still be in %zone_name.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', '%random_inventory_item_link? yeah, sure, that\'s totally gonna carry you.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'you\'re a %my_class? no wonder you\'re bad.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', '%my_race players should just uninstall.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'what\'s it like being carried every game?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'bro, did you buy your account or what?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'who invited the %my_level noob?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'you\'re about as useful as %random_inventory_item_link.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'you playing with one hand, or are you just that bad?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'i\'ve seen %random_inventory_item_link with more DPS than you.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'bruh, even murlocs hit harder than you.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'just delete %my_class and reroll.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'didn\'t know this raid came with a comedy act.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'how much gold did you pay for that boost?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'playing %my_role? guess it\'s carry time.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'imagine being bad at %zone_name.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', '%my_class players are basically NPCs.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'your damage is lower than my IQ.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'is there a “report for being bad” button yet?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'bro, did you forget to equip your gear?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'you\'re the reason we can\'t have nice things.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'if trash mobs could talk, they\'d roast you.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'bet you died to fall damage in %zone_name.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'you\'re like a gray item—worthless.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'bro, even a training dummy dodged your attack.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'if there was an achievement for failing, you\'d have it.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'this is why pugs have trust issues.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'you\'re the MVP of doing nothing.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'this dungeon is harder because you exist.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'your heals are as rare as a %random_inventory_item_link drop.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'you bring the vibe down worse than an Old God.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'did your pet press your cooldowns for you?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'you\'re as useless as fishing in a raid.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'your DPS makes critters look scary.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'the boss is laughing at your damage.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'you\'ve been AFK so long, I thought you died IRL.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'i bet you roll need on gray items.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'this group would be better without you.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'i could tank better as %my_class.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'you must be playing on your sibling\'s account.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'you\'re the only person I know who dies to critters.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'your gear is better than your skill.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'you\'re like a quest mob—easy to kill and forgotten.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'you must be the tutorial boss of this group.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'your rotation is as random as loot rolls.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'if you\'re the healer, why are we all dead?', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'you pull mobs like a toddler pulls toys.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'next time, just stay in Stormwind.', 0, 0, '', '', '', '', '', '', '', ''),
('suggest_something_toxic', 'bro, your gear score means nothing if you can\'t dodge AoEs.', 0, 0, '', '', '', '', '', '', '', '');
