INSERT INTO `ai_playerbot_texts` (`name`, `text`, `say_type`, `reply_type`, `text_loc1`, `text_loc2`, `text_loc3`, `text_loc4`, `text_loc5`, `text_loc6`, `text_loc7`, `text_loc8`) VALUES
('thunderfury_spam', '%thunderfury_link', 0, 0, '', '.', '', '', '', '', '', ''),
('thunderfury_spam', '%thunderfury_link%thunderfury_link', 0, 0, '', '', '', '', '', '', '', ''),
('thunderfury_spam', '%thunderfury_link%thunderfury_link%thunderfury_link', 0, 0, '', '', '', '', '', '', '', ''),
('thunderfury_spam', 'I think I just heard %thunderfury_link', 0, 0, '', 'J’ai entendu %thunderfury_link', 'Ich glaube, ich habe gerade %thunderfury_link gehört.', '', '', '', '', ''),
('thunderfury_spam', 'I think I heard %thunderfury_link', 0, 0, '', 'Je viens juste d’entendre %thunderfury_link', 'Ich glaube, ich habe %thunderfury_link gehört.', '', '', '', '', ''),
('thunderfury_spam', 'I definitely heard %thunderfury_link', 0, 0, '', 'Je suis sûr d’avoir entendu parler de %thunderfury_link.', 'Ich bin mir sicher, dass ich %thunderfury_link gehört habe.', '', '', '', '', ''),
('thunderfury_spam', 'I dunno but I’m pretty sure I heard %thunderfury_link', 0, 0, '', 'Je ne sais pas, mais je suis presque certain d’avoir entendu %thunderfury_link.', 'Keine Ahnung, aber ich bin mir ziemlich sicher, dass ich %thunderfury_link gehört habe.', '', '', '', '', ''),
('thunderfury_spam', 'Did you just say %thunderfury_link', 0, 0, '', 'Qui vient de parler de %thunderfury_link?', 'Hast du gerade %thunderfury_link gesagt?', '', '', '', '', ''),
('thunderfury_spam', 'did someone say %thunderfury_link', 0, 0, '', 'Oh, vous avez mentionné %thunderfury_link ?', 'Hat jemand gerade %thunderfury_link erwähnt?', '', '', '', '', ''),
('thunderfury_spam', 'Did someone say %thunderfury_link ?', 0, 0, '', 'Qui a mentionné %thunderfury_link ?', 'Hat jemand %thunderfury_link gesagt?', '', '', '', '', ''),
('thunderfury_spam', 'Someone said %thunderfury_link', 0, 0, '', 'Quelqu’un a mentionné %thunderfury_link.', 'Jemand hat %thunderfury_link erwähnt.', '', '', '', '', ''),
('thunderfury_spam', '%thunderfury_link is coming out of the closet', 0, 0, '', '%thunderfury_link sort du placard', '%thunderfury_link kommt aus dem Schrank heraus.', '', '', '', '', ''),
('thunderfury_spam', 'could swear it was a %thunderfury_link, might have been %thunderfury_link tho', 0, 0, '', 'Je pourrais jurer que c’était un %thunderfury_link, mais ça aurait aussi pu être %thunderfury_link en fait.', 'Ich könnte schwören, es war ein %thunderfury_link, aber es könnte auch %thunderfury_link gewesen sein.', '', '', '', '', ''),
('thunderfury_spam', 'Why use %thunderfury_link when %thunderfury_link is clearly way more OP', 0, 0, '', 'Pourquoi utiliser %thunderfury_link quand %thunderfury_link est clairement beaucoup plus puissant.', 'Warum %thunderfury_link benutzen, wenn %thunderfury_link eindeutig viel stärker ist?', '', '', '', '', ''),
('thunderfury_spam', 'Did I just hear %thunderfury_link?', 0, 0, '', 'Ai-je juste entendu %thunderfury_link?', 'Habe ich gerade %thunderfury_link gehört?', '', '', '', '', ''),
('thunderfury_spam', 'No way... is that a %thunderfury_link I hear?', 0, 0, '', 'Pas possible... Est-ce que j’entends %thunderfury_link ?', 'Unmöglich... Habe ich da etwa %thunderfury_link gehört?', '', '', '', '', ''),
('thunderfury_spam', '%thunderfury_link? Sounds like something only legends wield!', 0, 0, '', '%thunderfury_link? Ça a l’air d’être quelque chose que seuls les légendes manient!', '%thunderfury_link? Klingt nach etwas, das nur Legenden führen!', '', '', '', '', ''),
('thunderfury_spam', 'I can feel the power of %thunderfury_link in the air!', 0, 0, '', 'Je peux sentir la puissance de %thunderfury_link dans l’air !', 'Ich kann die Macht von %thunderfury_link in der Luft spüren!', '', '', '', '', ''),
('thunderfury_spam', '%thunderfury_link is the *real* MVP', 0, 0, '', '%thunderfury_link est le *vrai* MVP.', '%thunderfury_link ist der *wahre* MVP.', '', '', '', '', ''),
('thunderfury_spam', 'Can someone get me a %thunderfury_link? Asking for a friend... maybe even two!', 0, 0, '', 'Est-ce que quelqu’un peut me trouver un %thunderfury_link ? Je demande pour un ami... peut-être même deux !', 'Kann mir jemand ein %thunderfury_link besorgen? Frage für einen Freund... oder zwei!', '', '', '', '', ''),
('thunderfury_spam', 'Hey, did %thunderfury_link just *smite* something? I swear I felt the ground shake.', 0, 0, '', 'Hey, est-ce que %thunderfury_link vient de *foudroyer* quelque chose ? Je te jure que j’ai senti la terre trembler.', 'Hey, hat %thunderfury_link gerade etwas *erschlagen*? Ich schwöre, ich habe den Boden beben gespürt.', '', '', '', '', ''),
('thunderfury_spam', '%thunderfury_link on the battlefield... It’s like an instant flex.', 0, 0, '', '%thunderfury_link sur le champ de bataille... C’est comme montrer sa puissance instantanément.', '%thunderfury_link auf dem Schlachtfeld... Das ist purer Flex.', '', '', '', '', ''),
('thunderfury_spam', 'I *think* I heard %thunderfury_link... Or was that just a myth?', 0, 0, '', '*Je crois* avoir entendu %thunderfury_link... Ou peut-être que c’était juste un mythe?', '*Ich glaube*, ich habe %thunderfury_link gehört... Oder war das nur ein Mythos?', '', '', '', '', ''),
('thunderfury_spam', 'Wait, did I just see someone wielding %thunderfury_link?!', 0, 0, '', 'Attends, est-ce que je viens de voir quelqu’un manier %thunderfury_link ?!', 'Warte mal, habe ich gerade jemanden gesehen, der %thunderfury_link führt?!', '', '', '', '', ''),
('thunderfury_spam', 'The power of %thunderfury_link is *undeniable*', 0, 0, '', 'Le pouvoir de %thunderfury_link est *indéniable*', 'Die Macht von %thunderfury_link ist *unbestreitbar*', '', '', '', '', ''),
('thunderfury_spam', 'I’m 99% sure that was %thunderfury_link. 1% might have been a random NPC, tho.', 0, 0, '', 'Je suis à 99% certain que c’était %thunderfury_link. Le 1% restant aurait pu être un PNJ aléatoire, cependant.', 'Ich bin zu 99% sicher, dass das %thunderfury_link war. Die restlichen 1% könnten ein zufälliger NPC gewesen sein.', '', '', '', '', ''),
('thunderfury_spam', '%thunderfury_link in action! Who needs an army when you’ve got that kind of power?', 0, 0, '', '%thunderfury_link en action ! Qui a besoin d’une armée lorsqu’on a ce genre de puissance ?', '%thunderfury_link in Aktion! Wer braucht eine Armee, wenn man so eine Macht hat?', '', '', '', '', ''),
('thunderfury_spam', 'I heard %thunderfury_link is what really brings all the boys to the yard.', 0, 0, '', 'J’ai entendu dire que %thunderfury_link, c’est ce qui attire vraiment tous les garçons dans la cour.', 'Ich habe gehört, dass %thunderfury_link wirklich alle Jungs in den Hof lockt.', '', '', '', '', ''),
('thunderfury_spam', 'Why even use %thunderfury_link when %thunderfury_link is clearly the superior option?', 0, 0, '', 'Pourquoi même utiliser %thunderfury_link quand %thunderfury_link est clairement l’option supérieure ?', 'Warum überhaupt %thunderfury_link benutzen, wenn %thunderfury_link klar die bessere Option ist?', '', '', '', '', ''),
('thunderfury_spam', 'Is it me or does %thunderfury_link have a “smack talk” passive effect?', 0, 0, '', 'Est-ce moi ou est-ce que %thunderfury_link a un effet passif de provocation ?', 'Bin ich der Einzige, oder hat %thunderfury_link eine passive “Trash Talk”-Fähigkeit?', '', '', '', '', ''),
('thunderfury_spam', 'I thought I heard %thunderfury_link, but it was just the sound of sheer awesome.', 0, 0, '', 'J’ai cru entendre %thunderfury_link, mais en fait c’était juste le son de la pure puissance.', 'Ich dachte, ich hätte %thunderfury_link gehört, aber es war nur der Klang reiner Epikness.', '', '', '', '', ''),
('thunderfury_spam', 'Oh, %thunderfury_link... Where *have* you been all my life?', 0, 0, '', 'Oh, %thunderfury_link ... Où as-tu été tout ce temps, ma belle épée ?', 'Oh, %thunderfury_link... Wo *warst* du mein ganzes Leben lang?', '', '', '', '', ''),
('thunderfury_spam', 'Did someone say %thunderfury_link? I think I need to go pick mine up.', 0, 0, '', '%thunderfury_link? Oh là là, j’entends toujours parler de cet incroyable objet! Je crois bien qu’il est temps pour moi d’aller le chercher.', 'Hat jemand %thunderfury_link gesagt? Ich glaube, ich muss meine jetzt auch abholen.', '', '', '', '', ''),
('thunderfury_spam', 'That was definitely the sound of %thunderfury_link! I can feel the epicness.', 0, 0, '', 'C’était certainement le son de %thunderfury_link ! Je peux sentir toute son épopée.', 'Das war definitiv der Klang von %thunderfury_link! Ich kann die Epikness spüren.', '', '', '', '', ''),
('thunderfury_spam', 'Is it just me, or does %thunderfury_link have a tendency to make everyone else *look* weak?', 0, 0, '', 'C’est moi ou bien %thunderfury_link a tendance à faire paraître les autres faibles?', 'Bin ich der Einzige, oder lässt %thunderfury_link alle anderen *schwach* aussehen?', '', '', '', '', ''),
('thunderfury_spam', 'You know what they say... the louder the %thunderfury_link, the bigger the bragging rights!', 0, 0, '', 'Tu sais ce qu’on dit... plus le %thunderfury_link rugit, plus grand sont les droits de vantardise!', 'Du weißt, was man sagt... je lauter das %thunderfury_link, desto größer die Prahlrechte!', '', '', '', '', ''),
('thunderfury_spam', '%thunderfury_link', 0, 0, '', '', '', '', '', '', '', ''),
('thunderfury_spam', '%thunderfury_link%thunderfury_link', 0, 0, '', '', '', '', '', '', '', ''),
('thunderfury_spam', '%thunderfury_link%thunderfury_link%thunderfury_link', 0, 0, '', '', '', '', '', '', '', ''),
('thunderfury_spam', 'I think I just heard %thunderfury_link', 0, 0, '', '', '', '', '', '', '', ''),
('thunderfury_spam', 'I think I heard %thunderfury_link', 0, 0, '', '', '', '', '', '', '', ''),
('thunderfury_spam', 'I definitely heard %thunderfury_link', 0, 0, '', '', '', '', '', '', '', ''),
('thunderfury_spam', 'I dunno but Im pretty sure I heard %thunderfury_link', 0, 0, '', '', '', '', '', '', '', ''),
('thunderfury_spam', 'Did you just say %thunderfury_link', 0, 0, '', '', '', '', '', '', '', ''),
('thunderfury_spam', 'did someone say %thunderfury_link', 0, 0, '', '', '', '', '', '', '', ''),
('thunderfury_spam', 'Did someone say %thunderfury_link ?', 0, 0, '', '', '', '', '', '', '', ''),
('thunderfury_spam', 'Someone said %thunderfury_link', 0, 0, '', '', '', '', '', '', '', ''),
('thunderfury_spam', '%thunderfury_link is coming out of the closet', 0, 0, '', '', '', '', '', '', '', ''),
('thunderfury_spam', 'could swear it was a %thunderfury_link, might have been %thunderfury_link tho', 0, 0, '', '', '', '', '', '', '', ''),
('thunderfury_spam', 'Why use %thunderfury_link when %thunderfury_link is clearly way more OP', 0, 0, '', '', '', '', '', '', '', '');
INSERT INTO `ai_playerbot_texts` (`name`, `text`, `say_type`, `reply_type`, `text_loc1`, `text_loc2`, `text_loc3`, `text_loc4`, `text_loc5`, `text_loc6`, `text_loc7`, `text_loc8`) VALUES
('suggest_sell', 'WTS %item_formatted_link for %cost_gold.', 0, 0, '', 'Je vends %item_formatted_link pour %cost_gold.', 'Verkaufe %item_formatted_link für %cost_gold.', '', '', 'Quiero vender %item_formatted_link por %cost_gold.', '', ''),
('suggest_sell', 'Who wants %item_formatted_link for %cost_gold?', 0, 0, '', 'Qui veut %item_formatted_link pour %cost_gold?', 'Wer will %item_formatted_link für %cost_gold?', '', '', '¿Quién quiere %item_formatted_link por %cost_gold?', '', ''),
('suggest_sell', 'Anyone wants %item_formatted_link? Only %cost_gold.', 0, 0, '', 'Est-ce que quelqu’un veut %item_formatted_link ? Seulement %cost_gold.', 'Will jemand %item_formatted_link? Nur %cost_gold.', '', '', '¿Alguien quiere %item_formatted_link? Solo %cost_gold.', '', ''),
('suggest_sell', 'Just %cost_gold for %item_formatted_link!', 0, 0, '', 'Juste %cost_gold pour %item_formatted_link!', 'Nur %cost_gold für %item_formatted_link!', '', '', '¡Solo %cost_gold para %item_formatted_link!', '', ''),
('suggest_sell', 'Selling %item_formatted_link for %cost_gold.', 0, 0, '', 'Je vends %item_formatted_link pour %cost_gold.', 'Verkaufe %item_formatted_link für %cost_gold.', '', '', 'Vendo %item_formatted_link por %cost_gold.', '', ''),
('suggest_sell', '%item_formatted_link is yours just for %cost_gold!', 0, 0, '', '%item_formatted_link est à toi pour seulement %cost_gold !', '%item_formatted_link gehört dir für nur %cost_gold!', '', '', '%item_formatted_link es tuyo solo por %cost_gold!', '', ''),
('suggest_sell', 'Ridiculus price of %cost_gold for %item_formatted_link!', 0, 0, '', 'Le prix ridicule de %cost_gold pour %item_formatted_link !', 'Lächerlicher Preis von %cost_gold für %item_formatted_link!', '', '', '¡Precio ridículo de %cost_gold para %item_formatted_link_link!', '', ''),
('suggest_sell', 'Wanna sell %item_formatted_link for %cost_gold.', 0, 0, '', 'Je veux vendre %item_formatted_link pour %cost_gold.', 'Möchte %item_formatted_link für %cost_gold verkaufen.', '', '', 'Quiero vender %item_formatted_link por %cost_gold.', '', ''),
('suggest_sell', 'Who needs %item_formatted_link? Only %cost_gold.', 0, 0, '', 'Qui a besoin de %item_formatted_link? Seulement %cost_gold.', 'Wer braucht %item_formatted_link? Nur %cost_gold.', '', '', '¿Quién necesita %item_formatted_link? Solo %cost_gold.', '', ''),
