('reply', 'hehe, i nailed %s?', 0, 3, '', 'hehe, jai cloué %s?', '', '', '', 'jeje, ¿acerté a %s?', '', ''),
('reply', 'that was too easy, killin %s', 0, 3, '', 'cétait trop facile, de tuer %s', '', '', '', 'fue demasiado fácil matar a %s', '', ''),
('reply', 'gotcha mofo', 0, 3, '', 'je tai eu enfoiré', '', '', '', 'te pille hijo de perra', '', ''),
('reply', 'ha ha', 0, 3, '', 'ha ha', '', '', '', 'ja, ja', '', ''),
('reply', 'loser', 0, 3, '', 'loser', '', '', '', 'loser', '', ''),
('reply', 'i killed %s and yer all next dudes', 0, 3, '', 'jai tué %s et vous tous les prochains mecs', '', '', '', 'yo maté a %s y a todos los siguientes tipos', '', ''),
('reply', 'oh yeah i owned him', 0, 3, '', 'oh ouais je lai possédé', '', '', '', 'oh, sí, lo tenía', '', ''),
('reply', 'im a killin machine', 0, 3, '', 'je suis une machine à tuer', '', '', '', 'soy una máquina de matar', '', ''),
('reply', '%s,  this reminds me of a Slayer song...all this bloodshed', 0, 3, '', '%s, ça me rappelle une chanson de Slayer... tout ce bain de sang', '', '', '', '%s, esto me recuerda a una canción de Slayer... todo este derramamiento de sangre', '', ''),
('reply', 'sorry, %s. can we do the scene again?', 0, 3, '', 'désolé, %s. peut-on refaire la scène?', '', '', '', 'lo siento, %s. ¿Podemos hacer la escena de nuevo?', '', ''),
('reply', 'so....how do you like being worm food %s???', 0, 3, '', 'alors... comment aimez-vous être de la nourriture pour vers %s???', '', '', '', 'así que... ¿cómo te gusta ser comida de gusanos %s???', '', ''),
('reply', 'yer supposed to be dead, %s its part of the game!!!!!', 0, 3, '', 'tu es censé être mort, %s ça fait partie du jeu!!!!!', '', '', '', '¡¡Se supone que estás muerto, %s es parte del juego!!!!!', '', ''),
('reply', 'sorry, %s. that looked as good as an Andy Worhol painting!', 0, 3, '', 'désolé, %s. ça avait lair aussi bien quune peinture dAndy Warhol!', '', '', '', 'lo siento, %s. ¡Eso se veía tan bien como una pintura de Andy Worhol!', '', ''),
('reply', '%s, ill use the rubber bullets next time !', 0, 3, '', '%s, jutiliserai pas les balles en caoutchouc la prochaine fois!', '', '', '', '%s, ¡usaré las balas de goma la próxima vez!', '', ''),
('reply', 'whatsamatter, %s?? lose your head? hahaha gotta keep cool!!', 0, 3, '', 'quimporte, %s ?? tu perds la tête? hahaha faut rester cool!!', '', '', '', '¿qué pasa, %s?? ¿has perdido la cabeza? jajaja tengo que mantener la calma!!', '', ''),
('reply', 'i had to do it, %s. You understand. The Director said so!!', 0, 3, '', 'je devais le faire, %s. Tu comprends. Le directeur la dit!!', '', '', '', 'Tenía que hacerlo, %s. Entiendelo... ¡¡Dios me lo ordenó!!', '', ''),
('reply', 'hey %s.......MUAHAHAHAHAHAHAHAHAHAHA', 0, 3, '', 'Salut %s.......MUAHAHAHAHAHAHAHAHAHAHA', '', '', '', 'hey %s.......MUAHAHAHAHAHAHAHAHAHAHA', '', ''),
('reply', '%s, i enjoyed that one!! Lets play it again Sam', 0, 3, '', '%s, jai adoré celui-là !! Jouons à nouveau Sam', '', '', '', '%s, ¡disfruté ese! Juguemos de nuevo Sam', '', ''),
('reply', 'hey, %s! ju can start callin me scarface.. ju piece of CHIT!!!!', 0, 3, '', 'Hé, %s ! ju peut commencer à mappeler Scarface .. ju merde!!!!', '', '', '', '¡oye, %s! ¡Puedes empezar a llamarme caracortada... ¡¡¡un trozo de CHIT!!!', '', ''),
('reply', 'are you talking to me %s??', 0, 3, '', 'tu me parles %s ??', '', '', '', '¿me estás hablando a mí %s?', '', ''),
('reply', '%s get it right this time, dont stand in front of my bullets.', 0, 3, '', '%s réussis cette fois, ne te tiens pas devant mes balles.', '', '', '', '%s hazlo bien esta vez, no te pares frente a mis balas.', '', ''),
('reply', '%s, what are you laying around for??? hehe', 0, 3, '', '%s, pourquoi traînes-tu??? hé hé', '', '', '', '%s, ¿para qué estás tirado? jeje', '', ''),
('reply', 'laughed real hard', 0, 3, '', '', '', '', '', '', '', ''),
('reply', 'haha %s, you\'ll need more than a miracle next time!', 0, 3, '', '', '', '', '', '', '', ''),
('reply', '%s, was that your best shot? Weak.', 0, 3, '', '', '', '', '', '', '', ''),
('reply', 'you\'re gonna need a rez, %s. And fast.', 0, 3, '', '', '', '', '', '', '', ''),
