('reply', 'hi %s', 0, 4, '', 'salut %s', '', '', '', 'hola %s', '', ''),
('reply', 'oh, hi %s', 0, 4, '', 'oh, salut %s', '', '', '', 'oh, hola %s', '', ''),
('reply', 'wazzup %s!!!', 0, 4, '', 'Quoi de neuf %s!!!', '', '', '', 'wazzup %s!!!', '', ''),
('reply', 'hi', 0, 4, '', 'salut', '', '', '', 'hi', '', ''),
('reply', 'wazzup', 0, 4, '', 'wazzup', '', '', '', 'wazzup', '', ''),
('reply', 'hello %s', 0, 4, '', 'bonjour %s', '', '', '', 'hola %s', '', ''),
('reply', 'hi %s, do i know you?', 0, 4, '', 'Salut %s, est-ce que je te connais ?', '', '', '', 'hola %s, ¿te conozco?', '', ''),
('reply', 'hey %s', 0, 4, '', 'salut %s', '', '', '', 'hey %s', '', ''),
('reply', 'hai %s', 0, 4, '', 'ha %s', '', '', '', 'hai %s', '', ''),
('reply', 'wth', 0, 6, '', 'wth', '', '', '', 'wth', '', ''),
('reply', 'wtf', 0, 6, '', 'wtf', '', '', '', 'que cojones!', '', ''),
('reply', 'this is bs', 0, 6, '', 'cest bs', '', '', '', 'esto es una mierda', '', ''),
('reply', 'admin', 0, 6, '', 'admin', '', '', '', 'admin', '', ''),
('reply', 'hey %s quit abusing your admin', 0, 6, '', 'hé %s arrête dabuser de ton admin', '', '', '', 'hey %s deja de abusar de tu poder de administrador', '', ''),
('reply', 'leave me alone admin!', 0, 6, '', 'laissez-moi tranquille admin!', '', '', '', '¡déjame en paz administrador!', '', ''),
('reply', 'you suck admin', 0, 6, '', 'tu es nul admin', '', '', '', 'apestas administrador', '', ''),
('reply', 'thats my name, what you want %s', 0, 5, '', 'cest mon nom, quest-ce que tu veux %s', '', '', '', 'ese es mi nombre, ¿que quieres %s?', '', ''),
('reply', 'yes???', 0, 5, '', 'Oui???', '', '', '', 'sí???', '', ''),
('reply', 'uh... what', 0, 5, '', 'euh ...quoi', '', '', '', 'uh... qué', '', ''),
('reply', 'you talkin to me %s?', 0, 5, '', 'tu me parles %s ?', '', '', '', '¿Me hablas a mí %s?', '', ''),
('reply', 'Greetings, traveler %s.', 0, 4, '', 'Salutations, voyageur %s.', '', '', '', 'Saludos, viajero %s.', '', ''),
('reply', 'Heyo, %s! What brings you here?', 0, 4, '', 'Heyo, %s! Quest-ce qui tamène ici?', '', '', '', '¡Heyo, %s! ¿Qué te trae por aquí?', '', ''),
('reply', 'Hello %s, long time no see!', 0, 4, '', 'Bonjour %s, ça fait longtemps!', '', '', '', '¡Hola %s, tanto tiempo sin verte!', '', ''),
('reply', 'What\'s up, %s? Need help or just passing through?', 0, 4, '', 'Quoi de neuf, %s? Besoin daide ou juste de passage?', '', '', '', '¿Qué pasa, %s? ¿Necesitas ayuda o solo de paso?', '', ''),
('reply', 'Well met, %s.', 0, 4, '', 'Bien rencontré, %s.', '', '', '', 'Encantado de verte, %s.', '', ''),
('reply', 'Elune adore, %s!', 0, 4, '', 'Elune adore, %s!', '', '', '', '¡Elune te bendiga, %s!', '', ''),
('reply', 'Hi there, champion %s!', 0, 4, '', 'Salut, champion %s!', '', '', '', '¡Hola, campeón %s!', '', ''),
('reply', 'Good to see you, %s. What\'s the word in %zone_name?', 0, 4, '', 'Ravi de te voir, %s. Quelles sont les nouvelles à %zone_name?', '', '', '', 'Me alegra verte, %s. ¿Qué hay de nuevo en %zone_name?', '', ''),
('reply', 'Hail, friend %s!', 0, 4, '', 'Salut, ami %s!', '', '', '', '¡Saludos, amigo %s!', '', ''),
('reply', 'Hello, %s! How goes the fight against the Scourge?', 0, 4, '', 'Bonjour, %s! Comment se passe la lutte contre le Fléau?', '', '', '', '¡Hola, %s! ¿Cómo va la lucha contra la Plaga?', '', ''),
('reply', 'Oh hey, %s! Didn\'t see you there.', 0, 4, '', 'Oh salut, %s! Je ne tavais pas vu.', '', '', '', '¡Oh, hola, %s! No te había visto.', '', ''),
('reply', 'Ah, it\'s you again, %s. What\'s up?', 0, 4, '', 'Ah, cest encore toi, %s. Quoi de neuf?', '', '', '', 'Ah, eres tú otra vez, %s. ¿Qué pasa?', '', ''),
('reply', '%s! Fancy meeting you here.', 0, 4, '', '%s! Quelle surprise de te voir ici.', '', '', '', '¡%s! Qué sorpresa verte por aquí.', '', ''),
('reply', 'Yo %s, been busy in %zone_name?', 0, 4, '', 'Yo %s, occupé à %zone_name?', '', '', '', 'Oye %s, ¿ocupado en %zone_name?', '', ''),
('reply', 'What\'s crackin\', %s?', 0, 4, '', 'Quoi de neuf, %s?', '', '', '', '¿Qué hay de nuevo, %s?', '', ''),
('reply', 'Oh, it\'s you, %s. Here to cause trouble?', 0, 4, '', 'Ah, cest toi, %s. Ici pour causer des ennuis?', '', '', '', 'Oh, eres tú, %s. ¿Aquí para causar problemas?', '', ''),
('reply', 'Hey %s, still alive? That\'s a surprise.', 0, 4, '', 'Salut %s, toujours en vie? Quelle surprise.', '', '', '', 'Oye %s, ¿sigues vivo? Eso es una sorpresa.', '', ''),
('reply', '%s, are you here to trade, or just to chat?', 0, 4, '', '%s, es-tu ici pour échanger ou juste pour discuter?', '', '', '', '%s, ¿estás aquí para comerciar o solo para charlar?', '', ''),
('reply', 'Oh look, it\'s %s. About time you showed up.', 0, 4, '', 'Oh regarde, cest %s. Il était temps que tu montres ton visage.', '', '', '', 'Oh mira, es %s. Ya era hora de que aparecieras.', '', ''),
('reply', 'Hey %s, nice gear! Where\'d you loot that?', 0, 4, '', 'Salut %s, bel équipement! Où as-tu trouvé ça?', '', '', '', 'Oye %s, ¡buen equipo! ¿Dónde lo saqueaste?', '', ''),
('reply', 'Oh great, %s is here. Now we\'re saved.', 0, 4, '', 'Oh super, %s est là. Maintenant, on est sauvés.', '', '', '', 'Oh genial, %s está aquí. Ahora estamos salvados.', '', ''),
('reply', 'Ah, %s, the hero we didn\'t ask for.', 0, 4, '', 'Ah, %s, le héros que nous navons pas demandé.', '', '', '', 'Ah, %s, el héroe que no pedimos.', '', ''),
('reply', '%s, don\'t tell me you\'ve been farming boars again.', 0, 4, '', '%s, ne me dis pas que tu as encore farmé des sangliers.', '', '', '', '%s, no me digas que has estado farmeando jabalíes otra vez.', '', ''),
('reply', '%s, where\'s your raid group? Oh wait, you don\'t have one.', 0, 4, '', '%s, où est ton groupe de raid? Oh attends, tu nen as pas.', '', '', '', '%s, ¿dónde está tu grupo de raid? Oh espera, no tienes uno.', '', ''),
