('reply', 'Wow, %s. Back already? Did you even restock your potions?', 0, 4, '', 'Wow, %s. Déjà de retour? As-tu même rechargé tes potions?', '', '', '', 'Vaya, %s. ¿Ya estás de vuelta? ¿Ni siquiera recargaste tus pociones?', '', ''),
('reply', 'Look alive, %s! Oh wait, you already are.', 0, 4, '', 'Reste en vie, %s! Oh attends, tu les déjà.', '', '', '', '¡Mira, %s! Ah espera, ya estás vivo.', '', ''),
('reply', '%s, you\'re about as sneaky as a tauren in a library.', 0, 4, '', '%s, tu es aussi discret quun tauren dans une bibliothèque.', '', '', '', '%s, eres tan sigiloso como un tauren en una biblioteca.', '', ''),
